import Swiper, { Navigation, Pagination, Scrollbar } from "swiper";
import { Fancybox } from "@fancyapps/ui";
import Aos from "aos";
Swiper.use([Navigation, Pagination, Scrollbar]);

document.body.addEventListener("click", (e) => {
  let target = e.target;

  if (target.dataset.table) changeTable(target);
  if (target.dataset.tabBtn) changeTab(target);
});

const changeTable = (target) => {
  const id = target.dataset.table;
  const table = document.querySelector(`[data-table-content="${id}"]`);
  const activeTable = document.querySelector(".services__table--active");
  const activeBtn = document.querySelector(".services__tab--active");
  if (table) {
    activeTable.classList.remove("services__table--active");
    table.classList.add("services__table--active");
  }
  activeBtn.classList.remove("services__tab--active");
  target.classList.add("services__tab--active");
};
const changeTab = (target) => {
  const id = target.dataset.tabBtn;
  const table = document.querySelector(`[data-tab="${id}"]`);
  const activeTable = document.querySelector(".tab.active");
  const activeBtn = document.querySelector(".beniffits__btn.active");

  if (table) {
    activeTable.classList.remove("active");
    table.classList.add("active");
  }
  activeBtn.classList.remove("active");
  target.classList.add("active");
};

window.addEventListener("scroll", (e) => {
  let scrollY = window.scrollY;

  if (scrollY >= 400) {
    document.querySelector(".header").classList.add("header--dark");
  } else {
    document.querySelector(".header").classList.remove("header--dark");
  }
});

if (document.querySelector(".projects__swiper")) {
  const _swiper = new Swiper(".projects__swiper", {
    slidesPerView: 4,
    spaceBetween: 20,

    breakpoints: {
      320: {
        slidesPerView: 1.2,
      },
      768: {
        slidesPerView: 2,
      },
      1024: {
        slidesPerView: 3.5,
      },
    },
  });
}

if (document.querySelector(".beniffits__swiper")) {
  document.querySelectorAll(".beniffits__swiper").forEach((item) => {
    const parent = item.closest(".slider");
    const prev = parent.querySelector(".btn-nav.prev");
    const next = parent.querySelector(".btn-nav.next");

    const _swiper = new Swiper(item, {
      slidesPerView: 4,
      spaceBetween: 20,

      navigation: {
        prevEl: prev,
        nextEl: next,
      },

      breakpoints: {
        320: {
          slidesPerView: 1,
        },
        768: {
          slidesPerView: 2,
        },
        1024: {
          slidesPerView: 3,
        },
        1200: {
          slidesPerView: 4,
        },
      },
    });
  });
}

Fancybox.bind('[data-fancybox="gallery-1"]', {
  Toolbar: {
    display: {
      left: ["infobar"],
      middle: ["zoomIn", "zoomOut", "rotateCCW", "rotateCW", "flipX", "flipY"],
      right: ["slideshow", "thumbs", "close"],
    },
  },
});

Aos.init();

// Cookie Banner
const cookieBanner = document.getElementById("cookieBanner");
const cookieAccept = document.getElementById("cookieAccept");

if (cookieBanner && !localStorage.getItem("cookieAccepted")) {
  setTimeout(() => {
    cookieBanner.classList.add("cookie-banner--active");
  }, 2000);
}

if (cookieAccept) {
  cookieAccept.addEventListener("click", () => {
    localStorage.setItem("cookieAccepted", "true");
    cookieBanner.classList.remove("cookie-banner--active");
  });
}

// Menu Modal
const menuModal = document.getElementById("menuModal");
const menuClose = document.getElementById("menuClose");
const openMenu = document.querySelector(".burger");

if (openMenu) {
  openMenu.addEventListener("click", (e) => {
    e.preventDefault();
    menuModal.classList.add("menu-active");
  });
}

if (menuClose) {
  menuClose.addEventListener("click", () => {
    menuModal.classList.remove("menu-active");
  });
}

// Close modal on outside click
if (menuModal) {
  menuModal.addEventListener("click", (e) => {
    if (e.target === menuModal) {
      menuModal.classList.remove("menu-active");
    }
  });
}

// Project Modal
const projectModal = document.getElementById("projectModal");
const projectModalClose = document.getElementById("projectModalClose");
const projectBtns = document.querySelectorAll(".projects__slide-btn");

const projectTitle = document.getElementById("projectModalTitle");
const projectImg = document.getElementById("projectModalImg");
const projectDesc = document.getElementById("projectModalDesc");

if (projectBtns.length > 0) {
  projectBtns.forEach((btn) => {
    btn.addEventListener("click", () => {
      const title = btn.getAttribute("data-project-title");
      const desc = btn.getAttribute("data-project-desc");
      const img = btn.getAttribute("data-project-img");

      projectTitle.textContent = title;
      projectDesc.textContent = desc;
      projectImg.src = img;
      projectImg.alt = title;

      projectModal.classList.add("active");
      document.body.style.overflow = "hidden"; // Disable scroll
    });
  });
}

if (projectModalClose) {
  projectModalClose.addEventListener("click", () => {
    projectModal.classList.remove("active");
    document.body.style.overflow = ""; // Enable scroll
  });
}

if (projectModal) {
  projectModal.addEventListener("click", (e) => {
    if (e.target === projectModal) {
      projectModal.classList.remove("active");
      document.body.style.overflow = "";
    }
  });
}
